  return parts.flatMap(part => {
    if (part.length <= MAX_TELEGRAM) return [part];
    const re = new RegExp(`.{1,${SAFE_BUDGET}}`, 'g');
    return part.match(re) || [];
  });
}

// ============ MAIN ============
const inputItems = $input.all();
const out = [];

for (const item of inputItems) {
  const j = item.json || {};

  // Datos dinámicos
  const name = j.Name || 'User';
  const cal = j.Total_Calories || 0;
  const calTarget = j.Calories_target || 1;

  const prot = j.Total_Proteins || 0;
  const protTarget = j.Protein_target || 1;

  const carbs = j.Total_Carbs || 0;
  const fats  = j.Total_Fats || 0;

  // Construcción del mensaje
  let msg = `*Hello ${name}*\nHere is your nutrition summary:\n\n`;

  msg += `🔥 *Calories*: ${cal}/${calTarget} (${percent(cal, calTarget)}%)\n`;
  msg += makeProgressBar(cal, calTarget) + '\n\n';

  msg += `🍗 *Protein*: ${prot}/${protTarget} (${percent(prot, protTarget)}%)\n`;
  msg += makeProgressBar(prot, protTarget) + '\n\n';

  msg += `🌾 *Carbs*: ${carbs} g\n`;
  msg += `🥑 *Fats*: ${fats} g\n`;

  // Formateo seguro
  const formatted = processMarkdownV2Safe(msg);
  const chunks = chunkForTelegram(formatted, SAFE_BUDGET);

  chunks.forEach((chunk, idx) => {
    out.push({
      json: {
        ...j,
        message: chunk,
        message_part_index: idx + 1,
        message_parts_total: chunks.length,
      },
      binary: item.binary,
    });
  });
}

return out;

// Get all input items
const items = $input.all();

// Initialize accumulators
let totalCalories = 0;
let totalProteins = 0;
let totalCarbs = 0;
let totalFats = 0;

// Sum up each field from every item
for (const item of items) {
  const data = item.json;

  totalCalories += Number(data.Calories || 0);
  totalProteins += Number(data.Proteins || 0);
  totalCarbs += Number(data.Carbs || 0);
  totalFats += Number(data.Fats || 0);
}

// Return a single result with totals
return [
  {
    json: {
      Total_Calories: totalCalories,
      Total_Proteins: totalProteins,
      Total_Carbs: totalCarbs,
      Total_Fats: totalFats,
    }
  }
];
